def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    epsilon = 1e-12
    for i, capacity in enumerate(bins):
        if capacity == 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        priority = 0.0
        if ratio > 3:
            base = (ratio ** 5) + (capacity % 4) * 3.7
            for a in range(1, int(capacity) + 3):
                if a % 3 == 0:
                    base += np.tan(min(ratio / (a + epsilon), np.pi / 4)) * np.exp(-a / (capacity + epsilon))
                elif a % 2 == 0:
                    base -= np.abs(np.sin(a * ratio)) / (a + epsilon)
                else:
                    base += np.log(a * ratio + 1 + epsilon) / (a + epsilon)
            if capacity % 5 == 0:
                priority = base * 1.3
            elif capacity % 2 == 1:
                priority = base / 1.2
            else:
                priority = base
        elif 2 < ratio <= 3:
            priority = (ratio ** 3) * np.sqrt(capacity + 1)
            acc = 0
            for b in range(1, int(item) * 2 + 1):
                if b % 4 == 1:
                    acc += np.power(b / (capacity + 1), 1.5)
                elif b % 4 == 2:
                    acc -= np.log(b + ratio + epsilon)
                elif b % 4 == 3:
                    acc += np.sin(b) / (b + epsilon)
                else:
                    acc -= np.cos(ratio * b)
            priority += acc
            priority = max(priority, 0)
        elif 1 < ratio <= 2:
            base = -np.log(1 - (ratio - 0.5)/2 + epsilon)
            scale = 1
            for c in range(1, 7):
                scale *= (ratio + c / (capacity + 1)) * (c / (item + 1))
                if scale > 7:
                    break
            priority = base * scale + np.sqrt(item * capacity) / (ratio + epsilon)
        elif 0.5 < ratio <= 1:
            priority = np.exp(-ratio) * np.log(capacity + 2)
            variance = 0
            for d in range(1, int(capacity) + 1):
                variance += ((-1)**d) * (ratio ** d) / (d + epsilon)
            priority += np.abs(variance)
            for e in range(1, int(item) + 1):
                if e % 2 == 0:
                    priority += np.power(e / (capacity + 1), 2)
                else:
                    priority -= np.sqrt(e + ratio)
        elif 0 < ratio <= 0.5:
            total = 0
            prod = 1
            for f in range(1, int(capacity) + 2):
                val = ((ratio ** f) / (f + epsilon)) * ((-1) ** (f+1))
                total += val
                prod *= (1 + val * 0.1)
                if prod > 10:
                    break
            priority = np.log(abs(total) + 1) * prod
            for g in range(1, int(item) + 3):
                if g % 3 == 0:
                    priority += np.exp(-g/(capacity+epsilon))
                else:
                    priority -= (g * ratio) / (item + epsilon)
        else:
            priority = 1 / (capacity + epsilon)
            for h in range(1, int(capacity) + 1):
                term = np.sin(ratio * h) * np.cos(h / (capacity + epsilon))
                if h % 2 == 0:
                    priority += term / (h + epsilon)
                else:
                    priority -= term / (h + epsilon)
            priority *= np.sqrt(item + capacity)
        if capacity < item:
            diff = item - capacity
            penalty = diff * 20
            logsum = 0
            for m in range(1, int(diff)+2):
                if m % 2 == 0:
                    logsum += np.log(m + ratio + epsilon)
                else:
                    logsum -= np.sqrt(m)
            penalty += max(logsum, 0)
            penalty *= np.exp(-diff / (item + epsilon))
            priority += penalty
        priorities[i] = priority
    return priorities
